from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a comics character into a fluent sentence.
    """
    if not triples:
        return ""

    phrase_parts = []
    for triple in triples:
        s, p, o = triple.subject, triple.predicate, triple.object

        # Normalise predicate to simple string for matching
        pred = p.lower()

        if pred == "alternativename":
            phrase = f"{s} is also known as {o}"
        elif pred == "creator":
            phrase = f"{s} was created by {o}"
        elif pred == "fullname":
            phrase = f"{s}'s full name is {o}"
        elif pred == "foundedby":
            phrase = f"{s} was founded by {o}"
        elif pred == "keyperson":
            phrase = f"{o} is a key person at {s}"
        elif pred == "city":
            phrase = f"{s} is located in {o}"
        elif pred == "product":
            phrase = f"{s} produces {o}"
        elif pred == "lastaired":
            phrase = f"The last episode of {s} aired on {o}"
        elif pred == "starring":
            phrase = f"{s} stars {o}"
        elif pred == "firstappearanceinfilm":
            phrase = f"{s} first appeared in the film {o}"
        elif pred == "voice":
            phrase = f"{o} provides the voice for {s}"
        elif pred == "distributor":
            phrase = f"{o} distributed {s}"
        elif pred == "birthplace":
            phrase = f"{s} was born in {o}"
        elif pred == "nationality":
            phrase = f"{s} is {o}"
        elif pred == "award":
            phrase = f"{s} received the {o}"
        elif pred == "broadcastedby":
            phrase = f"{s} was broadcasted by {o}"
        elif pred == "firstaired":
            phrase = f"{s} first aired on {o}"
        elif pred == "series":
            phrase = f"{s} is part of the series {o}"
        elif pred == "child":
            phrase = f"{s} has a child named {o}"
        else:
            phrase = f"{s} {p} {o}"

        phrase_parts.append(phrase)

    # Combine parts into a single readable sentence
    if len(phrase_parts) == 1:
        return phrase_parts[0] + "."
    elif len(phrase_parts) == 2:
        return f"{phrase_parts[0]} and {phrase_parts[1]}."
    else:
        return f"{', '.join(phrase_parts[:-1])}, and {phrase_parts[-1]}."

# EVOLVE-BLOCK-END

